INSERT INTO flow_application (
    application_no, applicant_id, approver_id, application_type,
    attendance_record_id, makeup_active_marker,
    start_time, end_time, reason, status
) VALUES (
    #{applicationNo}, #{applicantId}, #{approverId}, #{applicationType},
    #{attendanceRecordId}, #{makeupActiveMarker},
    #{startTime}, #{endTime}, #{reason}, #{status}
)

INSERT INTO approval_task (
    application_id, approval_level, approver_id, approver_name, status, activated_at
) VALUES (
    #{applicationId}, #{approvalLevel}, #{approverId}, #{approverName}, #{status}, #{activatedAt}
)

INSERT INTO approval_record (
    application_id, task_id, approval_level, approver_id, action, comment
) VALUES (
    #{applicationId}, #{taskId}, #{approvalLevel}, #{approverId}, #{action}, #{comment}
)

mapper.select:
SELECT SUM(CASE WHEN status = 'PENDING' THEN 1 ELSE 0 END) AS pending_count,
       SUM(CASE WHEN status = 'APPROVED' THEN 1 ELSE 0 END) AS approved_count,
       SUM(CASE WHEN status = 'REJECTED' THEN 1 ELSE 0 END) AS rejected_count
FROM flow_application
WHERE created_at >= #{startTime}
  AND created_at < #{endTime}

SELECT application_type, COUNT(*) AS application_count
FROM flow_application
WHERE created_at >= #{startTime}
  AND created_at < #{endTime}
GROUP BY application_type
ORDER BY application_count DESC, application_type

SELECT DATE(created_at) AS application_date, COUNT(*) AS application_count
FROM flow_application
WHERE created_at >= #{startTime}
  AND created_at < #{endTime}
GROUP BY DATE(created_at)
ORDER BY application_date
